def process_soap_request(xml_string, dtd_string):
    from lxml import etree
    from io import StringIO
    
    dtd = etree.DTD(StringIO(dtd_string))
    parser = etree.XMLParser(dtd_validation=True)
    xml_tree = etree.fromstring(xml_string, parser)
    
    if not dtd.validate(xml_tree):
        raise ValueError("XML did not pass DTD validation.")
    
    ns = {'soap': 'http://schemas.xmlsoap.org/soap/envelope/'}
    body = xml_tree.find('soap:Body', ns)
    if body is None:
        raise ValueError("SOAP Body not found in the request.")
    
    return body.text or etree.tostring(body, encoding='unicode')